{
  "parameters": "z.object({ targetPlayerName: z.string().describe("The username of the player to move toward and follow"), followDistanceBlocks: z.number().min(0).default(4).describe("The distance threshold to start moving toward the player"), stopRangeBlocks: z.number().min(0).default(2).describe("The proximity radius where the bot will stop moving and wait"), maxDurationMs: z.number().int().min(1000).max(600000).default(60000).describe("Maximum time in active milliseconds to maintain the follow behavior") })",
  "executionArgs": {
    "targetPlayerName": "Bot2",
    "followDistanceBlocks": 4,
    "stopRangeBlocks": 2,
    "maxDurationMs": 60000
  },
  "code": "const targetName = args.targetPlayerName;
const pollMs = 500;
if (!bot.players[targetName]) {
  return '<NO TARGET>: Player ' + targetName + ' is not on the player list.';
}
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is not in a states to move.';
}
startBackgroundSkill(bot, 'move_to_player', async function (token) {
  let activeTimeSpent = 0;
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);
  try {
    while (canContinueBotAction(bot, token) && activeTimeSpent < args.maxDurationMs) {
      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      const player = bot.players[targetName];
      if (!player) break;
      const targetEntity = player.entity;
      if (!targetEntity) {
        bot.pathfinder.setGoal(null);
        if (!await waitForActiveMs(bot, token, 1000, 50)) return;
        activeTimeSpent += 1000;
        continue;
      }
      const currentDist = bot.entity.position.distanceTo(targetEntity.position);
      if (currentDist > args.followDistanceBlocks) {
        const goal = new goals.GoalFollow(targetEntity, args.stopRangeBlocks);
        bot.pathfinder.setGoal(goal);
      } else if (currentDist <= args.stopRangeBlocks) {
        bot.pathfinder.setGoal(null);
        bot.pathfinder.stop();
      }
      if (!await waitForActiveMs(bot, token, pollMs, 50)) return;
      activeTimeSpent += pollMs;
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.pathfinder.stop();
  }
});
return '<STARTED>: Moving toward player ' + targetName + ' to maintain proximity.';"
}
